(function(){function OnePageNav(elem,options){this.elem=elem;this.options=Object.assign({},OnePageNav.defaults,options);this.navItems=this.elem.querySelectorAll(this.options.navItems);this.sections={};this.didScroll=false;this.docHeight=document.documentElement.scrollHeight;this.t=null;this.handleClick=this.handleClick.bind(this);this.handleScroll=this.handleScroll.bind(this);this.getPositions=this.getPositions.bind(this)}OnePageNav.defaults={navItems:"a",currentClass:"current",changeHash:false,scrollSpeed:750,scrollThreshold:.5,scrollOffset:0,padding:0};OnePageNav.prototype={init:function(){this.navItems.forEach(function(item){item.addEventListener("click",this.handleClick)}.bind(this));this.getPositions();this.bindInterval();window.addEventListener("resize",this.getPositions);return this},adjustNav:function(parent){var current=this.elem.querySelector("."+this.options.currentClass);if(current)current.classList.remove(this.options.currentClass);parent.classList.add(this.options.currentClass)},bindInterval:function(){var self=this;window.addEventListener("scroll",self.handleScroll);self.t=setInterval(function(){var docHeight=document.documentElement.scrollHeight;if(self.didScroll){self.didScroll=false;self.scrollChange()}if(docHeight!==self.docHeight){self.docHeight=docHeight;self.getPositions()}},250)},handleScroll:function(){this.didScroll=true},getPositions:function(){var self=this;self.sections={};self.navItems.forEach(function(link){var hash=link.getAttribute("href").split("#")[1];var target=document.getElementById(hash);if(target){self.sections[hash]=Math.round(target.getBoundingClientRect().top+window.pageYOffset)}})},getSection:function(windowPos){var returnValue=null;var windowHeight=Math.round(window.innerHeight*this.options.scrollThreshold);for(var section in this.sections){if(this.sections[section]-windowHeight<windowPos){returnValue=section}}return returnValue},handleClick:function(e){var self=this;var link=e.currentTarget;var parent=link.parentElement;var newLoc="#"+link.getAttribute("href").split("#")[1];if(!parent.classList.contains(self.options.currentClass)){self.adjustNav(parent);self.unbindInterval();self.scrollTo(newLoc,function(){if(self.options.changeHash){window.location.hash=newLoc}self.bindInterval()})}e.preventDefault()},scrollChange:function(){var windowTop=window.pageYOffset;var position=this.getSection(windowTop);if(position!==null){var link=this.elem.querySelector('a[href$="#'+position+'"]');if(link){var parent=link.parentElement;if(!parent.classList.contains(this.options.currentClass)){this.adjustNav(parent)}}}},scrollTo:function(target,callback){var el=document.querySelector(target);if(!el)return;var offset=el.getBoundingClientRect().top+window.pageYOffset-this.options.padding;window.scrollTo({top:offset,behavior:"smooth"});setTimeout(callback,this.options.scrollSpeed)},unbindInterval:function(){clearInterval(this.t);window.removeEventListener("scroll",this.handleScroll)}};window.OnePageNav=OnePageNav})();